// Heavy weapon inventory (collected via 2% drop)
let hwInventory = {}; // {hw_id: count}

function spawnHeavyWeapon(x, y) {
  if (Math.random() > 0.02) return; // 2% chance
  const hw = HEAVY_WEAPONS[Math.floor(Math.random() * HEAVY_WEAPONS.length)];
  powerups.push({ x, y, type: 'heavy_weapon', hwId: hw.id, icon: hw.icon, color: '#ffe600', vy: 1.2, life: 400, r: 16, label: hw.name });
}

function getUpgradePrice(item) {
  const lvl = upgrades[item.id] || 0;
  return Math.floor(item.basePrice * Math.pow(item.priceScale, lvl));
}

