// ==================== CANVAS & 8K ULTRA QUALITY ====================
const cv = document.getElementById('c'), ctx = cv.getContext('2d', { alpha: true });
let W, H;

// ULTRA 8K Quality Setup
const dpr = Math.min(window.devicePixelRatio || 1, 2); // Cap at 2x for performance
function resize() { 
  W = window.innerWidth;
  H = window.innerHeight;
  cv.width = W * dpr;
  cv.height = H * dpr;
  // Scale canvas rendering context for 8K-like quality
  ctx.scale(dpr, dpr);
  cv.style.width = W + 'px';
  cv.style.height = H + 'px';
}
resize(); 
window.addEventListener('resize', resize);

// Canvas rendering quality enhancements
ctx.imageSmoothingEnabled = true;
ctx.imageSmoothingQuality = 'high';
ctx.lineCap = 'round';
ctx.lineJoin = 'round';

// ==================== FPS MONITOR + PARTICLE CAP ====================
let _fpsLast = performance.now(), _fpsFrames = 0, currentFPS = 60;
let PARTICLE_CAP = 350; // dynamic, reduces on low FPS but increases at high effect quality
function tickFPS() {
  _fpsFrames++;
  const now = performance.now();
  if (now - _fpsLast >= 1000) {
    currentFPS = _fpsFrames;
    _fpsFrames = 0; _fpsLast = now;
    
    // Base particle cap based on FPS
    let baseCap = 350;
    if (currentFPS < 30) baseCap = 120;
    else if (currentFPS < 45) baseCap = 200;
    
    // Adjust cap based on effect quality (use typeof check for safety)
    if (typeof effectQuality !== 'undefined' && typeof EFFECT_QUALITY_SETTINGS !== 'undefined') {
      const settings = EFFECT_QUALITY_SETTINGS[effectQuality] || EFFECT_QUALITY_SETTINGS.medium;
      PARTICLE_CAP = Math.ceil(baseCap * settings.particleMult);
    } else {
      PARTICLE_CAP = baseCap;
    }
  }
}
// Safe particle push — enforces cap
function pushParticle(p) {
  if (particles.length < PARTICLE_CAP) particles.push(p);
}

const EX = () => W / 2, EY = () => H - 105, ER = () => Math.min(W, H) * .08;

