function getDmgMult() { return 1 + (upgrades.dmg || 0) * 0.5; }
function getFireRateMult() { return 1 - (upgrades.fire || 0) * 0.15; }
function getRegenMult() { return 1 + (upgrades.regen || 0) * 1.5; }

