let floatingTexts = [];
function showFloatingText(text, x, y, color, isDmg) {
  // isDmg: faster rise, larger, shorter life for damage numbers
  floatingTexts.push({
    text: text, x: x, y: y, color: color || '#ffff00',
    life: isDmg ? 38 : 60,
    maxLife: isDmg ? 38 : 60,
    vy: isDmg ? -2.2 : -1.5,
    size: isDmg ? 13 : 11,
    bold: isDmg
  });
}
function showDmgText(dmg, x, y) {
  var col = dmg >= 100 ? '#ff2200' : dmg >= 50 ? '#ff6600' : dmg >= 20 ? '#ffaa00' : '#ffdd00';
  showFloatingText('-' + dmg, x, y, col, true);
}

