function buildAlienEncyclopedia() {
  const el = document.getElementById('alien-encyc');
  if (!el) return;
  let html = '';
  let lastSection = null;
  ALIEN_CATALOG.forEach(a => {
    if (a.section && a.section !== lastSection) {
      lastSection = a.section;
      html += '<div class="encyc-section-title">' + a.section + '</div>';
    }
    const stars = '★'.repeat(a.stars) + '☆'.repeat(5 - a.stars);
    html += '<div class="alien-row' + (a.isBoss ? ' boss-row' : '') + '">' +
      '<span class="ar-icon">' + a.icon + '</span>' +
      '<div class="ar-info">' +
      '<div class="ar-name">' + a.name + '</div>' +
      '<div class="ar-desc">' + a.desc + '</div>' +
      '<div class="ar-rating">' + stars + ' ' + a.rating + '</div>' +
      '</div></div>';
  });
  el.innerHTML = html;
}

